function(g, rect, comp, data, view) {var { x, y, width, height } = rect;

var scrollBarWidth = comp.getValue('scrollBarWidth') || 6;
var scrollBarColor = comp.getValue('scrollBarColor') || "#54bdf8";
var translateX = comp.getValue('translateX') || 0;
var translateY = comp.getValue('translateY') || 0;
var rows = comp.getValue('rows') || [];
var rowHeight = comp.getValue('rowHeight') || 0;
var drawRow = comp.getValue('drawRow');
var autoHideScrollBar = comp.getValue('autoHideScrollBar');


var bodyRect = {
    x: x,
    y: y,
    width: width,
    height: height
}
var contentSize = {
    width: width,
    height: rowHeight * rows.length
}
var offset = {
    x: translateX,
    y: translateY
};



// draw row item
g.save();
g.beginPath();
g.rect(x, y, width, height)
g.clip();
for (var i = 0; i < rows.length; i++) {
    var rowRect = {
        x: offset.x,
        y: offset.y + i * rowHeight,
        width: width,
        height: rowHeight
    }
    
    if (drawRow) {
        drawRow(g, rows[i], rowRect, data, view)
    }
    else {
        ht.Default.drawText(g, rows[i], '12px Arial', 'red', rowRect.x, rowRect.y, rowRect.width, rowRect.height, 'center', 'middle')
    }

}
g.restore();

var scrollVisible = true;
if(autoHideScrollBar && !comp._scrollVisible){
    scrollVisible = false
}
drawScrollBar(g, bodyRect, contentSize, offset, {
    visible: scrollVisible,
    color: scrollBarColor,
    barWidth: scrollBarWidth
});


function drawScrollBar(g, bodyRect, contentSize, offset, option = {}) {
    var { x, y, width, height } = bodyRect,
        contentWidth = contentSize.width,
        contentHeight = contentSize.height,
        ox = offset.x,
        oy = offset.y,
        minX, minY, xRect = null, yRect = null, scaleX, scaleY;
    var { color = 'red', barWidth = 8, gap = 2, visible } = option;
    g.save();
    // scroll bar y
    if (contentHeight > height) {
        scaleY = height / contentHeight;
        let barHeight = height * scaleY,
            barOffsetY = - oy * scaleY,
            bx = x + width - barWidth - gap,
            by = y + barOffsetY;

        yRect = [bx, by, barWidth, Math.max(barHeight, 16)];
        minY = height - contentHeight;
        if (visible) {
            g.beginPath();
            ht.Default.drawRoundRect(g, ...yRect, Math.min(barWidth, barHeight) / 2);
            g.fillStyle = color;
            g.fill();
        }
    }
    // scroll bar x
    if (contentWidth > width) {
        scaleX = width / contentWidth;
        var barHeight = width * scaleX,
            barOffsetX = - ox * scaleX,
            by = y + height - barWidth - gap,
            bx = x + barOffsetX;

        xRect = [bx, by, Math.max(barHeight, 16), barWidth];
        minX = width - contentWidth;
        if (visible) {
            g.beginPath();
            ht.Default.drawRoundRect(g, ...xRect, Math.min(barWidth, barHeight) / 2);
            g.fillStyle = color;
            g.fill();
        }
    }

    comp.__cunstomScrollInfo = {
        minX, minY,
        scrollBarY: yRect,
        scrollBarX: xRect
    }
    g.restore();
}}

events.onScroll:
function(event, data, view, point, width, height) {var scope = this;
handleScroll(event, data, view, point, width, height);

function handleScroll(event, data, view, point, width, height) {
    var scrollInfo = scope.__cunstomScrollInfo;
    if(!scrollInfo){
        return
    }
    var scrollSpeed = 1;
    var tyName, txName;
    tyName = getBindingInfo(scope, 'translateY', data);
    txName = getBindingInfo(scope, 'translateX', data);
    if (!scrollInfo) return;
    var { scrollBarX, scrollBarY, minX, minY } = scrollInfo;
    var deltaX = (event.wheelDeltaX || -event.deltaX || 0) / 40 * 5 * scrollSpeed;
    var deltaY = (event.wheelDeltaY || -event.deltaY || 0) / 40 * 5 * scrollSpeed;
    var deal = false;
    if (scrollBarY && tyName && deltaY) {
        var ty = (data.a(tyName) || 0) + deltaY;
        ty = Math.min(0, ty);
        ty = Math.max(minY, ty);
        data.a(tyName, ty);
        deal = true;
    }
    if (scrollBarX && txName && deltaX) {
        var tx = (data.a(txName) || 0) + deltaX;
        tx = Math.min(0, tx);
        tx = Math.max(minX, tx);
        data.a(txName, tx);
        deal = true;
    }
    if (!deal && scrollBarX && !scrollBarY && txName && deltaY) {
        var tx = (data.a(txName) || 0) + deltaY;
        tx = Math.min(0, tx);
        tx = Math.max(minX, tx);
        data.a(txName, tx);
    }
    data.iv();
}

function getBindingInfo(comp, attributeName, data, view) {
    if (!comp) {
        return;
    }
    var attr = comp[attributeName];
    const prefix = data.getCurrentPrefix();
    if (attr && attr.func) {
        if (typeof attr.func === 'string') {
            var arr = attr.func.split('@'),
                [accessType, name] = arr;
            return (prefix || '') + name;
        }
    }
    return null;
}}
